const item = $input.first().json;
const msg = item.message;

const hasVoice = !!(msg.voice || msg.audio);
const voiceFileId = msg.voice?.file_id || msg.audio?.file_id || null;

return [{
  json: {
    sessionId: String(msg.chat.id),
    debounce: {
      keyPrefix: 'telegram-chat-bot',
      windowSeconds: 15,
      timezone: 'Asia/Almaty'
    },
    provider: {
      name: 'telegram',
      channel: 'telegram_chat'
    },
    conversation: {
      id: String(msg.chat.id)
    },
    sender: {
      id: String(msg.chat.id),
      name: msg.chat.first_name || 'User'
    },
    message: {
      id: String(msg.message_id),
      type: hasVoice ? 'voice' : 'text',
      text: msg.text || '',
      voiceFileId: voiceFileId,
      hasVoice: hasVoice
    },
    timestamps: {
      receivedAt: new Date(msg.date * 1000).toISOString()
    },
    env: 'dev'
  }
}];

// Get data from Normalize Input (not set_current_date which only has currentDate)
const item = $('Normalize Input').first().json;
const date = $input.first().json.currentDate;

const debounceKey = `${item.debounce.keyPrefix}:${item.provider.name}:${item.provider.channel}:${item.env}:${item.conversation.id}`;

const messageData = {
  ...item.message,
  date: date,
  senderName: item.sender.name
};

return [{
  json: {
    ...item,
    debounceKey: debounceKey,
    debounceValue: JSON.stringify(messageData)
  }
}];

const item = $input.first().json;
let messagesRaw = item.message;

if (!messagesRaw) {
  return [];
}

// Handle both array and string formats from Redis
let messages = [];
if (Array.isArray(messagesRaw)) {
  // Redis returned an array
  messages = messagesRaw.map(m => {
    try {
      return typeof m === 'string' ? JSON.parse(m) : m;
    } catch(e) {
      return null;
    }
  }).filter(m => m !== null);
} else if (typeof messagesRaw === 'string') {
  // Redis returned a comma-separated string
  messages = messagesRaw.split(',').map(m => {
    try {
      return JSON.parse(m);
    } catch(e) {
      return null;
    }
  }).filter(m => m !== null);
} else {
  // Single object
  messages = [messagesRaw];
}

messages.sort((a, b) => new Date(a.date) - new Date(b.date));

const textMessages = messages.filter(m => m.text).map(m => m.text).join('\n\n');
const voiceMsg = messages.find(m => m.voiceFileId);

// Get sessionId from debounce_data
const debounceData = $('debounce_data').first().json;

return [{
  json: {
    sessionId: debounceData.sessionId,
    userName: debounceData.sender?.name || 'User',
    combinedText: textMessages,
    hasVoice: !!voiceMsg,
    voiceFileId: voiceMsg?.voiceFileId || null,
    messageCount: messages.length
  }
}];

const items = $input.all();
let trans = '';
let orig = '';
let sessionId = '';
let userName = '';
let hadVoice = false;

for (const item of items) {
  if (item.json.text) trans = item.json.text;
  if (item.json.combinedText !== undefined) orig = item.json.combinedText;
  if (item.json.sessionId) sessionId = item.json.sessionId;
  if (item.json.userName) userName = item.json.userName;
  if (item.json.hasVoice) hadVoice = item.json.hasVoice;
}

let chatInput = '';
if (trans && orig) {
  chatInput = `Текст: ${orig}\n\nГолос: ${trans}`;
} else if (trans) {
  chatInput = trans;
} else {
  chatInput = orig;
}

return [{
  json: {
    chatInput: chatInput,
    sessionId: sessionId,
    userName: userName,
    hadVoice: hadVoice
  }
}];
